"use client";

import { FormEvent, useState } from "react";
import { Clock3, Mail, MapPin, Phone } from "lucide-react";
import PageHero from "@/components/PageHero";
import SectionReveal from "@/components/SectionReveal";
import { SITE } from "@/lib/constants";
import styles from "./page.module.css";

type SubmitState = "idle" | "success" | "error";

export default function ContactPage() {
  const [state, setState] = useState<SubmitState>("idle");
  const [submitting, setSubmitting] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const form = event.currentTarget;
    const data = new FormData(form);

    if ((data.get("website") as string)?.length) {
      return;
    }

    setSubmitting(true);
    setState("idle");

    const payload = {
      name: (data.get("name") as string) || "",
      email: (data.get("email") as string) || "",
      phone: (data.get("phone") as string) || "",
      subject: (data.get("subject") as string) || "",
      message: (data.get("message") as string) || "",
      website: "",
    };

    try {
      const response = await fetch("/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        throw new Error("Submit failed");
      }

      setState("success");
      form.reset();
    } catch {
      setState("error");
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <>
      <PageHero
        title="Contact"
        subtitle="Questions, facility onboarding, and booking support from our dispatch team."
        breadcrumb="Contact"
      />

      <section className="section">
        <div className={`container ${styles.layout}`}>
          <SectionReveal className={styles.infoCol}>
            <h2>Reach Dispatch and Support</h2>
            <p>
              We are here to help with booking, scheduling updates, and facility
              coordination requests.
            </p>

            <div className={styles.infoCards}>
              <article className={`card ${styles.infoCard}`}>
                <Phone size={18} />
                <div>
                  <strong>Dispatch 24/7</strong>
                  <a href={`tel:${SITE.phoneHref}`}>{SITE.phoneDisplay}</a>
                </div>
              </article>

              <article className={`card ${styles.infoCard}`}>
                <Mail size={18} />
                <div>
                  <strong>Email</strong>
                  <a href={`mailto:${SITE.emailGeneral}`}>{SITE.emailGeneral}</a>
                  <a href={`mailto:${SITE.emailBookings}`}>{SITE.emailBookings}</a>
                </div>
              </article>

              <article className={`card ${styles.infoCard}`}>
                <Clock3 size={18} />
                <div>
                  <strong>Operating Hours</strong>
                  <span>{SITE.hours}</span>
                </div>
              </article>

              <article className={`card ${styles.infoCard}`}>
                <MapPin size={18} />
                <div>
                  <strong>Coverage Region</strong>
                  <span>Norfolk and Haldimand County</span>
                </div>
              </article>
            </div>
          </SectionReveal>

          <SectionReveal className={`card ${styles.formCard}`} delay={80}>
            <h3>Send a Message</h3>
            <p>We typically respond within one business day.</p>

            {state === "success" && (
              <p className={styles.success}>Message sent successfully.</p>
            )}
            {state === "error" && (
              <p className={styles.error}>Unable to send message. Please try again.</p>
            )}

            <form onSubmit={handleSubmit} className={styles.form}>
              <input name="website" autoComplete="off" tabIndex={-1} className={styles.honeypot} />

              <label>
                Name
                <input name="name" required />
              </label>

              <div className={styles.row}>
                <label>
                  Email
                  <input name="email" type="email" required />
                </label>
                <label>
                  Phone
                  <input name="phone" type="tel" />
                </label>
              </div>

              <label>
                Subject
                <input name="subject" required />
              </label>

              <label>
                Message
                <textarea name="message" rows={5} required />
              </label>

              <button className="btn btn-primary btn-pill" type="submit" disabled={submitting}>
                {submitting ? "Sending..." : "Send Message"}
              </button>
            </form>
          </SectionReveal>
        </div>
      </section>
    </>
  );
}
